func countTicks(every, total time.Duration) int {
	t := time.NewTicker(every)
	defer t.Stop()
	deadline := time.After(total)
	n := 0
	for {
		select {
		case <-t.C:
			n++
		case <-deadline:
			return n
		}
	}
}

func main() {
	fmt.Println(countTicks(time.Millisecond, 5*time.Millisecond) >= 0)
}
